    43→    let mut watch_paths = vec![cards_dir.join(watch_subdir)];
    44→
    45→    // Discover team-* directories
    46→    if let Ok(entries) = fs::read_dir(&cards_dir) {
    47→        for entry in entries.flatten() {
    48→            if let Ok(name) = entry.file_name().into_string() {
    49→                if name.starts_with("team-") {
    50→                    let team_watch = cards_dir.join(&name).join(watch_subdir);
    51→                    if team_watch.exists() {
    52→                        watch_paths.push(team_watch);
    53→                    }
