    77→    <string>3</string>"#
    78→            .to_string();
    79→    }
    80→
    81→    let args_block = if extra_args.is_empty() {
    82→        format!(
    83→            r#"    <string>{bin}</string>
    84→    <string>{sub}</string>"#,
    85→            bin = bop_bin.display(),
    86→            sub = subcommand,
