   112→
   113→  <key>ProgramArguments</key>
   114→  <array>
   115→{args}
   116→  </array>
   117→
   118→  <key>WorkingDirectory</key>
   119→  <string>{wd}</string>
   120→
   121→  <key>EnvironmentVariables</key>
   122→  <dict>
