    56→/// Validate events.jsonl integrity. Returns (valid, parse_errors, has_start, has_terminal, card_count).
    57→/// Extracted for testability — the public cmd_events_check wraps this with process::exit calls.
    58→pub(crate) fn check_events_file(content: &str) -> (usize, usize, bool, bool, usize) {
    59→    let mut valid = 0usize;
    60→    let mut parse_errors = 0usize;
    61→    let mut cards: std::collections::HashSet<String> = std::collections::HashSet::new();
    62→    let mut has_start = false;
    63→    let mut has_terminal = false;
    64→
    65→    for line in content.lines() {
    66→        if line.trim().is_empty() {
    67→            continue;
    68→        }
    69→        match serde_json::from_str::<bop_core::lineage::RunEvent>(line) {
    70→            Ok(ev) => {
    71→                valid += 1;
    72→                cards.insert(ev.job.name.clone());
    73→                match ev.event_type {
    74→                    bop_core::lineage::EventType::Start => has_start = true,
    75→                    bop_core::lineage::EventType::Complete
    76→                    | bop_core::lineage::EventType::Fail
    77→                    | bop_core::lineage::EventType::Abort => has_terminal = true,
    78→                    _ => {}
    79→                }
    80→            }
    81→            Err(_) => parse_errors += 1,
    82→        }
    83→    }
    84→    (valid, parse_errors, has_start, has_terminal, cards.len())
    85→}
