    87→pub fn cmd_events_check(root: &Path) -> anyhow::Result<()> {
    88→    let events_path = root.join("events.jsonl");
    89→    if !events_path.exists() {
    90→        println!("WARN: no events.jsonl — lineage not enabled or never triggered");
    91→        std::process::exit(1);
    92→    }
    93→
    94→    let content = fs::read_to_string(&events_path)?;
    95→    let (valid, parse_errors, has_start, has_terminal, card_count) = check_events_file(&content);
    96→
    97→    println!(
    98→        "{} events, {} cards, {} parse errors",
    99→        valid, card_count, parse_errors
   100→    );
   101→
   102→    if valid == 0 {
   103→        println!("WARN: events.jsonl exists but contains no valid events");
   104→        std::process::exit(1);
   105→    }
   106→    if parse_errors > 0 {
   107→        println!("WARN: {} lines failed to parse", parse_errors);
   108→    }
   109→    if !has_start {
   110→        println!("WARN: no START events found");
   111→    }
   112→    if !has_terminal {
   113→        println!("WARN: no terminal events (COMPLETE/FAIL/ABORT) found");
   114→    }
   115→
   116→    if parse_errors == 0 && has_start && has_terminal {
   117→        println!("OK");
   118→    } else {
   119→        std::process::exit(1);
   120→    }
   121→
   122→    Ok(())
   123→}
