fn install_hooks_macos(cards_root: &std::path::Path, uninstall: bool) -> anyhow::Result<()> {
    use std::process::Command as StdCommand;

    let home = std::env::var("HOME").context("HOME not set")?;
    let la_dir = PathBuf::from(&home).join("Library/LaunchAgents");
    let dest = la_dir.join("sh.bop.merge-gate.plist");

    if uninstall {
        // Uninstall: unload and remove the plist
        if dest.exists() {
            let out = StdCommand::new("launchctl")
                .args(["unload"])
                .arg(&dest)
                .output()?;

            if out.status.success() {
                println!("✓ unloaded sh.bop.merge-gate");
            } else {
                eprintln!(
                    "⚠ launchctl unload failed: {}",
                    String::from_utf8_lossy(&out.stderr)
                );
            }

            fs::remove_file(&dest)?;
            println!("✓ removed {}", dest.display());
        } else {
            println!("⚠ no hook installed at {}", dest.display());
        }
        return Ok(());
    }

    // Install: resolve repo root (cards_root is .cards, parent is repo)
    let repo_root = fs::canonicalize(cards_root)
        .unwrap_or_else(|_| cards_root.to_path_buf())
        .parent()
        .map(|p| p.to_path_buf())
        .unwrap_or_else(|| PathBuf::from("."));

    let repo_root = if cards_root
        .file_name()
        .map(|f| f == ".cards")
        .unwrap_or(false)
    {
        cards_root
            .parent()
            .unwrap_or(std::path::Path::new("."))
            .to_path_buf()
    } else {
        repo_root
    };
    let repo_root = fs::canonicalize(&repo_root).unwrap_or(repo_root);

    // Read the template
    let template_path = repo_root.join("install/macos/sh.bop.merge-gate.plist");
    let template = fs::read_to_string(&template_path)
        .with_context(|| format!("Failed to read template from {}", template_path.display()))?;

    // Discover team-* directories for WatchPaths
    let cards_dir = repo_root.join(".cards");
    let mut watch_paths = vec![cards_dir.join("done")];

    if let Ok(entries) = fs::read_dir(&cards_dir) {
        for entry in entries.flatten() {
            if let Ok(name) = entry.file_name().into_string() {
                if name.starts_with("team-") {
                    let team_watch = cards_dir.join(&name).join("done");
                    if team_watch.exists() {
                        watch_paths.push(team_watch);
                    }
                }
            }
        }
    }

    // Build WatchPaths XML
    let watch_paths_xml = watch_paths
        .iter()
        .map(|p| format!("    <string>{}</string>", p.display()))
        .collect::<Vec<_>>()
        .join("\n");

    // Replace placeholders
    let mut plist = template.replace("REPLACE_WITH_REPO_ROOT", repo_root.to_str().unwrap_or("."));
    plist = plist.replace("REPLACE_WITH_HOME", &home);

    // Replace the WatchPaths section with our dynamically generated paths
    // Find and replace the WatchPaths array content
    if let Some(start) = plist.find("<key>WatchPaths</key>") {
        if let Some(array_start) = plist[start..].find("<array>") {
            if let Some(array_end) = plist[start + array_start..].find("</array>") {
                let before = &plist[..start + array_start + 7]; // +7 for "<array>"
                let after = &plist[start + array_start + array_end..];
                plist = format!("{}\n{}\n  {}", before, watch_paths_xml, after);
            }
        }
    }

    // Get current executable path for ProgramArguments
    let bop_bin = std::env::current_exe().unwrap_or_else(|_| PathBuf::from("/usr/local/bin/bop"));
    plist = plist.replace(
        "/usr/local/bin/bop",
        bop_bin.to_str().unwrap_or("/usr/local/bin/bop"),
    );

    // Add --once flag if not present
    if !plist.contains("--once") {
        plist = plist.replace(
            "    <string>merge-gate</string>",
            "    <string>merge-gate</string>\n    <string>--once</string>",
        );
    }

    // Write to LaunchAgents
    let la_dir = PathBuf::from(&home).join("Library/LaunchAgents");
    fs::create_dir_all(&la_dir)?;

    let dest = la_dir.join("sh.bop.merge-gate.plist");
    fs::write(&dest, &plist)?;
    println!("✓ wrote {}", dest.display());

    // Load with launchctl
    let out = StdCommand::new("launchctl")
        .args(["load", "-w"])
        .arg(&dest)
        .output()?;

    if out.status.success() {
        println!("✓ loaded sh.bop.merge-gate");
    } else {
        eprintln!(
            "⚠ launchctl load failed: {}",
            String::from_utf8_lossy(&out.stderr)
        );
    }

    Ok(())
}

